use std::collections::VecDeque;

fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let mut visited = vec![vec![false; n]; m];
    let mut count = 0;
    let directions = [(-1, 0), (1, 0), (0, -1), (0, 1)];

    for i in 0..m {
        for j in 0..n {
            if grid[i][j] > 0 && !visited[i][j] {
                let mut queue = VecDeque::new();
                queue.push_back((i, j));
                visited[i][j] = true;
                let mut sum = 0;
                while let Some((x, y)) = queue.pop_front() {
                    sum += grid[x][y];
                    for (dx, dy) in directions {
                        let nx = x as i64 + dx;
                        let ny = y as i64 + dy;
                        if nx >= 0 && nx < m as i64 && ny >= 0 && ny < n as i64 {
