                            let ny = ny as usize;
                            if !visited[nx][ny] && grid[nx][ny] > 0 {
                                visited[nx][ny] = true;
                                queue.push_back((nx, ny));
                            }
                        }
                    }
                }
                if sum % k == 0 {
                    count += 1;
                }
            }
        }
    }
    count
}
